import{_ as d,o as a,c as e,a2 as l}from"./chunks/framework.DZrHScmQ.js";const b=JSON.parse('{"title":"Skill Catalog","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/agent-system/skills/skill-catalog.md","filePath":"ai-native/agent-system/skills/skill-catalog.md"}'),r={name:"ai-native/agent-system/skills/skill-catalog.md"};function o(i,t,h,s,c,n){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="skill-catalog" tabindex="-1">Skill Catalog <a class="header-anchor" href="#skill-catalog" aria-label="Permalink to &quot;Skill Catalog&quot;">​</a></h1><p><strong>状态：Draft</strong></p><h2 id="文档与知识" tabindex="-1">文档与知识 <a class="header-anchor" href="#文档与知识" aria-label="Permalink to &quot;文档与知识&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>用途</th><th>适合场景</th><th>注意</th></tr></thead><tbody><tr><td><code>deep-research</code></td><td>多源研究和事实核查</td><td>需要引用、对比、验证的研究问题</td><td>问题太宽时先澄清</td></tr><tr><td><code>verify</code></td><td>手动验证变更是否真的工作</td><td>UI、交互、端到端行为</td><td>不替代自动测试</td></tr><tr><td><code>run</code></td><td>启动项目或应用观察结果</td><td>需要截图、运行效果或真实 app 行为</td><td>先确认启动方式</td></tr><tr><td><code>code-review</code></td><td>Review 当前 diff</td><td>合并前找 bug 和风险</td><td>实现者和 Reviewer 最好分上下文</td></tr><tr><td><code>simplify</code></td><td>简化改动、减少重复</td><td>代码已能工作但偏复杂</td><td>不负责找 correctness bug</td></tr></tbody></table><h2 id="claude-code-工作流" tabindex="-1">Claude Code 工作流 <a class="header-anchor" href="#claude-code-工作流" aria-label="Permalink to &quot;Claude Code 工作流&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>用途</th><th>适合场景</th><th>注意</th></tr></thead><tbody><tr><td>Plan Mode</td><td>先探索再写计划</td><td>多文件、架构、需求不清</td><td>不要用于 typo 小改</td></tr><tr><td>Explore subagent</td><td>只读搜索和定位</td><td>需要扫很多文件但不想污染主上下文</td><td>只要结论，不要全文 dump</td></tr><tr><td>Worktree</td><td>隔离修改</td><td>并行实验或高风险重构</td><td>只有明确需要时使用</td></tr><tr><td>Hook</td><td>强制动作</td><td>lint、权限、审计、禁止路径</td><td>先验证流程稳定再升级成 Hook</td></tr></tbody></table><h2 id="mcp-外部系统" tabindex="-1">MCP / 外部系统 <a class="header-anchor" href="#mcp-外部系统" aria-label="Permalink to &quot;MCP / 外部系统&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>用途</th><th>适合场景</th><th>注意</th></tr></thead><tbody><tr><td>GitHub MCP</td><td>Issue、PR、Review 操作</td><td>需要创建 PR 或查仓库元数据</td><td>写操作先 dry-run</td></tr><tr><td>Feishu CLI / MCP</td><td>飞书消息和文档操作</td><td>团队协作、通知、任务入口</td><td>不写入 token；外部发送前确认</td></tr><tr><td>Browser / UI 工具</td><td>观察真实界面</td><td>验证交互和视觉</td><td>记录截图或可复现路径</td></tr></tbody></table><h2 id="外部-skill-stack" tabindex="-1">外部 Skill Stack <a class="header-anchor" href="#外部-skill-stack" aria-label="Permalink to &quot;外部 Skill Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>用途</th><th>适合场景</th><th>注意</th></tr></thead><tbody><tr><td><a href="https://github.com/garrytan/gstack" target="_blank" rel="noreferrer">gstack</a></td><td>Claude Code skill stack 参考</td><td>想快速参考一组现成 skills / workflows</td><td>先读源码和权限边界，不直接复制进生产工作区</td></tr></tbody></table><h2 id="加入新-skill-的标准" tabindex="-1">加入新 Skill 的标准 <a class="header-anchor" href="#加入新-skill-的标准" aria-label="Permalink to &quot;加入新 Skill 的标准&quot;">​</a></h2><ul><li>至少在一个真实任务中用过。</li><li>能说清楚输入、输出和完成标准。</li><li>不依赖个人密钥或私有路径。</li><li>有失败边界：什么时候不要用。</li></ul>',12)])])}const u=d(r,[["render",o]]);export{b as __pageData,u as default};
